@AbapCatalog.viewEnhancementCategory: [#NONE]
@AccessControl.authorizationCheck: #NOT_REQUIRED
@EndUserText.label: 'Items da Delivery da NFe'
@Metadata.ignorePropagatedAnnotations: true
define view entity /EXEDMINB/I_NFEMINBDELIVERY
  as select from /EXEDMINB/I_NFEHEADER  as _NFe
    inner join   I_DeliveryDocument     as _DeliveryDocument     on _NFe.delivery = _DeliveryDocument.DeliveryDocument
    inner join   I_DeliveryDocumentItem as _DeliveryDocumentItem on _DeliveryDocument.DeliveryDocument = _DeliveryDocumentItem.DeliveryDocument

  association to parent /EXEDMINB/I_NFEMONITORLOGH as _Header on _Header.ChaveNFe = $projection.ChaveNFe
{
  key _NFe.Id                            as ChaveNFe,
  key _DeliveryDocument.DeliveryDocument as Delivery,
  key _DeliveryDocumentItem.DeliveryDocumentItem,
      _DeliveryDocument.PickingDate      as DataRemessa,
      _DeliveryDocumentItem.Material,
      _DeliveryDocumentItem.Plant,
      _DeliveryDocumentItem.StorageLocation,
      _DeliveryDocumentItem.DeliveryDocumentItemText,

      _DeliveryDocumentItem.DeliveryQuantityUnit,
      @Semantics.quantity.unitOfMeasure: 'DeliveryQuantityUnit'
      _DeliveryDocumentItem.ActualDeliveryQuantity,
      @Semantics.quantity.unitOfMeasure: 'DeliveryQuantityUnit'
      _DeliveryDocumentItem.OriginalDeliveryQuantity,

      _DeliveryDocumentItem.PurchaseOrder,
      _DeliveryDocumentItem.PurchaseOrderItem,

      _Header


}
